export interface AnalysisMetric {
  name: string;
  score: number; // 0-10
  description: string;
}

export interface AnalysisResult {
  globalScore: number;
  metrics: AnalysisMetric[];
  visualHotspots: string[];
  critique: string;
  technicalMetadata: {
    sharpness: string;
    lighting: string;
    colorPalette: string[];
  };
}

export enum AppState {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult } from '../types';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }
  return new GoogleGenAI({ apiKey });
};

// Define the schema for the JSON response
const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    globalScore: {
      type: Type.NUMBER,
      description: "A floating point score between 0.0 and 10.0 representing the overall artistic and technical quality.",
    },
    metrics: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING, description: "Name of the metric (e.g., 'Composition', 'Color Harmony')" },
          score: { type: Type.NUMBER, description: "Score from 0.0 to 10.0" },
          description: { type: Type.STRING, description: "Brief justification for the score" },
        },
        required: ["name", "score", "description"]
      },
    },
    visualHotspots: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of key visual elements or focal points that draw the eye.",
    },
    critique: {
      type: Type.STRING,
      description: "A professional critique of the image emphasizing composition, lighting, and impact.",
    },
    technicalMetadata: {
      type: Type.OBJECT,
      properties: {
        sharpness: { type: Type.STRING, description: "Assessment of image clarity/sharpness" },
        lighting: { type: Type.STRING, description: "Assessment of lighting quality" },
        colorPalette: { 
          type: Type.ARRAY, 
          items: { type: Type.STRING }, 
          description: "List of hex codes representing the dominant color palette" 
        },
      },
      required: ["sharpness", "lighting", "colorPalette"]
    }
  },
  required: ["globalScore", "metrics", "visualHotspots", "critique", "technicalMetadata"],
};

export const analyzeImage = async (base64Image: string, mimeType: string): Promise<AnalysisResult> => {
  const ai = getAiClient();

  // Using gemini-2.5-flash-latest as per guidelines for general image tasks unless high res is needed
  // However, for complex reasoning on aesthetics, we can use the pro model if available, but flash is faster.
  // The system instruction specifies 'gemini-2.5-flash-image' for general image generation/editing, 
  // but for multimodal analysis 'gemini-2.5-flash' (or its latest alias) is suitable.
  // We will use 'gemini-2.5-flash-latest' mapped from 'gemini flash' guidance.
  const modelId = 'gemini-2.5-flash-latest';

  const prompt = `
    Act as a senior Art Director and Technical Photography Critic. 
    Analyze the provided image for its aesthetic quality, composition, and technical execution.

    Evaluate the following specific metrics:
    1. Compositional Balance (Rule of thirds, symmetry, golden ratio usage)
    2. Color Harmony (Palette coherence, saturation, contrast)
    3. Lighting Quality (Exposure, dynamic range, mood)
    4. Subject Definition (Clarity of focus, isolation of subject)

    Provide a rigorous, unbiased scoring.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image
            }
          },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        temperature: 0.4, // Lower temperature for more consistent/analytical results
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response received from the model.");
    }

    return JSON.parse(text) as AnalysisResult;
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

import React, { useCallback, useRef } from 'react';
import { Upload, Image as ImageIcon, X } from 'lucide-react';

interface ImageUploaderProps {
  onImageSelect: (file: File) => void;
  selectedImage: File | null;
  onClear: () => void;
  isAnalyzing: boolean;
}

export const ImageUploader: React.FC<ImageUploaderProps> = ({ 
  onImageSelect, 
  selectedImage, 
  onClear,
  isAnalyzing
}) => {
  const inputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      onImageSelect(e.dataTransfer.files[0]);
    }
  }, [onImageSelect]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onImageSelect(e.target.files[0]);
    }
  };

  if (selectedImage) {
    return (
      <div className="relative group rounded-xl overflow-hidden border-2 border-slate-700 bg-slate-900 shadow-2xl transition-all">
        <img 
          src={URL.createObjectURL(selectedImage)} 
          alt="Analysis Target" 
          className="w-full h-96 object-contain bg-black/50"
        />
        {!isAnalyzing && (
          <button 
            onClick={onClear}
            className="absolute top-4 right-4 p-2 bg-red-500/80 hover:bg-red-600 text-white rounded-full transition-colors backdrop-blur-sm"
          >
            <X className="h-5 w-5" />
          </button>
        )}
        {isAnalyzing && (
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center">
             <div className="flex flex-col items-center space-y-4">
                <div className="relative w-20 h-20">
                  <div className="absolute inset-0 border-4 border-indigo-500/30 rounded-full"></div>
                  <div className="absolute inset-0 border-4 border-t-indigo-500 rounded-full animate-spin"></div>
                </div>
                <p className="text-indigo-400 font-medium animate-pulse">Processing Biomarkers...</p>
             </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div 
      onDragOver={handleDragOver}
      onDrop={handleDrop}
      onClick={() => inputRef.current?.click()}
      className="border-2 border-dashed border-slate-700 hover:border-indigo-500 hover:bg-slate-800/50 rounded-2xl p-12 transition-all cursor-pointer group flex flex-col items-center justify-center h-80 bg-slate-900/50"
    >
      <input 
        type="file" 
        ref={inputRef} 
        onChange={handleFileChange} 
        accept="image/*" 
        className="hidden" 
      />
      <div className="p-4 bg-slate-800 rounded-full mb-4 group-hover:scale-110 transition-transform duration-300 ring-4 ring-slate-800 group-hover:ring-indigo-500/20">
        <Upload className="h-8 w-8 text-indigo-400" />
      </div>
      <h3 className="text-lg font-semibold text-slate-200 mb-2">Initialize Image Ingestion</h3>
      <p className="text-slate-400 text-sm text-center max-w-xs">
        Drag and drop your high-resolution file here, or click to browse.
        <br/><span className="text-slate-500 text-xs mt-2 block">Supported formats: JPEG, PNG, WEBP</span>
      </p>
    </div>
  );
};

