              style={{ width: `${(result.globalScore / 10) * 100}%` }}
            />
          </div>
        </div>

        <div className="md:col-span-2 bg-slate-800/50 rounded-xl p-6 border border-slate-700 backdrop-blur-sm">
          <h3 className="text-sm font-medium text-slate-400 uppercase tracking-wider mb-4">Metric Breakdown</h3>
          <div className="h-40 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={radarData} layout="vertical" margin={{ left: 100, right: 20 }}>
                <XAxis type="number" domain={[0, 10]} hide />
                <YAxis type="category" dataKey="subject" width={140} tick={{ fill: '#94a3b8', fontSize: 12 }} />
