             </div>
             <div className="flex flex-wrap gap-2">
               {result.visualHotspots.map((spot, idx) => (
                 <span key={idx} className="px-3 py-1 bg-indigo-500/10 text-indigo-300 border border-indigo-500/30 rounded-full text-sm">
                   {spot}
                 </span>
               ))}
             </div>
          </div>
        </div>

        {/* Right Column: Metadata & Radar */}
        <div className="space-y-6">
          <div className="bg-slate-800/50 rounded-xl p-6 border border-slate-700 flex flex-col items-center justify-center">
             <h3 className="text-sm font-medium text-slate-400 uppercase tracking-wider mb-2 self-start">Aesthetic Fingerprint</h3>
             <div className="h-64 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <RadarChart cx="50%" cy="50%" outerRadius="80%" data={radarData}>
                  <PolarGrid stroke="#334155" />
                  <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 10 }} />
                  <PolarRadiusAxis angle={30} domain={[0, 10]} tick={false} axisLine={false} />
