import React, { useState } from 'react';
import { Header } from './components/Header';
import { ImageUploader } from './components/ImageUploader';
import { AnalysisView } from './components/AnalysisView';
import { AppState, AnalysisResult } from './types';
import { analyzeImage } from './services/geminiService';
import { AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const convertFileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (typeof reader.result === 'string') {
          // Remove data URL prefix (e.g., "data:image/jpeg;base64,")
          const base64String = reader.result.split(',')[1];
          resolve(base64String);
        } else {
          reject(new Error("Failed to process image data"));
        }
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const handleImageSelect = (file: File) => {
    setSelectedImage(file);
    setAppState(AppState.IDLE);
    setResult(null);
    setError(null);
  };

  const handleClear = () => {
    setSelectedImage(null);
    setAppState(AppState.IDLE);
    setResult(null);
    setError(null);
  };

  const runAnalysis = async () => {
    if (!selectedImage) return;

    setAppState(AppState.ANALYZING);
    setError(null);

    try {
      const base64Data = await convertFileToBase64(selectedImage);
      const analysisData = await analyzeImage(base64Data, selectedImage.type);
      setResult(analysisData);
      setAppState(AppState.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setAppState(AppState.ERROR);
      setError(err.message || "An unexpected error occurred during analysis.");
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-200 font-sans selection:bg-indigo-500/30">
      <Header />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-8">

        {/* Intro Section - only show if no result yet */}
        {!result && (
          <div className="text-center max-w-2xl mx-auto mb-12">
            <h2 className="text-3xl font-bold text-white mb-4">Precision Visual Analytics</h2>
            <p className="text-slate-400 text-lg">
              Upload any image to extract deep aesthetic metrics, composition scores, and color harmony data powered by advanced computer vision.
            </p>
          </div>
        )}

        {/* Upload Section */}
        <div className="max-w-3xl mx-auto">
          <ImageUploader 
            onImageSelect={handleImageSelect}
            selectedImage={selectedImage}
            onClear={handleClear}
            isAnalyzing={appState === AppState.ANALYZING}
          />

          {/* Action Button */}
          {appState === AppState.IDLE && selectedImage && (
            <div className="mt-6 flex justify-center animate-fade-in-up">
              <button
                onClick={runAnalysis}
                className="bg-indigo-600 hover:bg-indigo-500 text-white text-lg font-semibold py-3 px-8 rounded-full shadow-lg shadow-indigo-500/30 transition-all hover:scale-105 active:scale-95 flex items-center"
              >
                Start Analysis Sequence
              </button>
            </div>
          )}
        </div>

        {/* Error State */}
        {appState === AppState.ERROR && (
          <div className="max-w-3xl mx-auto bg-red-500/10 border border-red-500/40 rounded-lg p-4 flex items-center gap-3">
            <AlertTriangle className="h-5 w-5 text-red-400 flex-shrink-0" />
            <p className="text-red-200">{error}</p>
          </div>
        )}

        {/* Results Section */}
        {appState === AppState.SUCCESS && result && (
          <div className="pt-8 border-t border-slate-800">
             <AnalysisView result={result} />
          </div>
        )}
      </main>

      <footer className="border-t border-slate-800 bg-slate-900 py-8 mt-12">
        <div className="max-w-7xl mx-auto px-4 text-center text-slate-500 text-sm">
          <p>&copy; {new Date().getFullYear()} AestheticLens. Scientific Composition Analysis.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

