  const prompt = `
    Act as a senior Art Director and Technical Photography Critic. 
    Analyze the provided image for its aesthetic quality, composition, and technical execution.

    Evaluate the following specific metrics:
    1. Compositional Balance (Rule of thirds, symmetry, golden ratio usage)
    2. Color Harmony (Palette coherence, saturation, contrast)
    3. Lighting Quality (Exposure, dynamic range, mood)
    4. Subject Definition (Clarity of focus, isolation of subject)

    Additionally, provide deep analysis on:
    5. Visual Complexity: Assess the density of detail, texture, and element count. (Score 0 for minimal, 10 for hyper-complex).
    6. Emotional Impact: Identify the mood, atmosphere, and emotional resonance. (Score 0 for clinical/neutral, 10 for deeply moving).

    Provide a rigorous, unbiased scoring.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image
            }
          },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        temperature: 0.4, // Lower temperature for more consistent/analytical results
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response received from the model.");
    }

    return JSON.parse(text) as AnalysisResult;
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

